			t.Fatalf("parse bead JSON: %v", err)
		}
		if got.Parent != "bx-001" {
			t.Errorf("MCP create: expected parent=bx-001, got %q", got.Parent)
		}
	})

	t.Run("MCP/set custom field survives create", func(t *testing.T) {
